               std::getline(inputFile, family)) {
            std::cout << std::left << std::setw(17) << speciesName << "| " << std::setw(15) << commonName << "| " << family << "\n";
        }
        inputFile.close();
    } else {
        std::cerr << "Error: Unable to open file " << fileName << std::endl;
    }
}

int main() {
