import Foundation

func calculateTimeDifference(from date: Date) -> (seconds: Int, minutes: Int, hours: Int, days: Int, weeks: Int, months: Int, years: Int) {
    let calendar = Calendar.current
    let now = Date()
    let components = calendar.dateComponents([.second, .minute, .hour, .day, .weekOfYear, .month, .year], from: date, to: now)

    let seconds = components.second ?? 0
    let minutes = components.minute ?? 0
    let hours = components.hour ?? 0
    let days = components.day ?? 0
    let weeks = components.weekOfYear ?? 0
    let months = components.month ?? 0
    let years = components.year ?? 0

    return (seconds, minutes, hours, days, weeks, months, years)
}

