{
    IMessagePipeConfigurator AddFilter(Func<Message, bool> filter);
    IMessagePipeConfigurator AddTransformer(Func<Message, Message> transformer);
    IMessagePipeConfigurator SetErrorHandler(Action<Exception, Message> errorHandler);
    IMessagePipe Build();
}
```

