fn max_width_difference(left_widths: Vec<u32>, right_widths: Vec<u32>) -> u32 {
    let max_width_1 = left_widths.iter().max().unwrap_or(&0);
    let max_width_2 = right_widths.iter().max().unwrap_or(&0);
    let min_width_1 = left_widths.iter().min().unwrap_or(&0);
    let min_width_2 = right_widths.iter().min().unwrap_or(&0);

    let max_diff_1 = max_width_1 - min_width_2;
    let max_diff_2 = max_width_2 - min_width_1;

    u32::max(max_diff_1, max_diff_2)
}

