impl ReminderSystem {
    fn new() -> Self {
        ReminderSystem { reminders: Vec::new() }
    }

    fn pop_last(&mut self) {
        self.reminders.pop();
    }

    fn continue_reminder(&mut self, index: usize) {
        self.reminders.push(format!("Reminder {}", index));
    }

    fn edit_reminder(&mut self, index: usize, new_text: &str) {
        if let Some(reminder) = self.reminders.get_mut(index) {
            *reminder = new_text.to_string();
        }
    }

    fn edit_last_reminder(&mut self, new_text: &str) {
        if let Some(last) = self.reminders.last_mut() {
            *last = new_text.to_string();
        }
    }

    fn edit_all_reminders(&mut self) {
        for reminder in &mut self.reminders {
            *reminder += " - Updated";
        }
    }

    fn get_reminder(&self, index: usize) -> Option<&String> {
        self.reminders.get(index)
    }

    fn get_last_reminder(&self) -> Option<&String> {
        self.reminders.last()
    }

    fn remind(&self, index: usize) {
        if let Some(reminder) = self.reminders.get(index) {
            println!("{}", reminder);
        }
    }

    fn remind_last(&self) {
        if let Some(last) = self.reminders.last() {
            println!("{}", last);
        }
    }
}

fn main() {
    let mut reminder_system = ReminderSystem::new();
    reminder_system.continue_reminder(1);
    reminder_system.continue_reminder(2);
    reminder_system.edit_reminder(1, "Updated Reminder");
    reminder_system.edit_last_reminder("New Last Reminder");
