    pattern = r'^(?P<remote_host>\S+) - (?P<user_name>\S+) \[(?P<timestamp>.*?)\] "(?P<request_method>\S+) (?P<request_url>\S+) (?P<request_protocol>.*?)" (?P<response_status_code>\d+) (?P<response_size>\S+)$'
