Your task is to complete the `a_star_search` function to implement the A* search algorithm using the provided `Position` class and the `heuristic_cost_estimate` function. The `grid` parameter represents the 2D array grid where 0 denotes an empty cell and 1 denotes a blocked cell. You need to implement the A* search algorithm to find the shortest path from the `start` position to the `goal` position on the grid.

```python
from typing import List, Dict, Tuple, Any
import heapq

def reconstruct_path(came_from: Dict[Position, Position], current: Position) -> List[Position]:
    total_path = [current]
    while current in came_from.keys():
        current = came_from[current]
        total_path.insert(0, current)
    return total_path

def a_star_search(grid: List[List[int]], start: Position, goal: Position) -> List[Position]:
    if start is None: 
        raise Exception("Start is None")

    if goal is None:
        raise Exception("goal is None")

    if start == goal:
        return [start]

    open_set = []
    heapq.heappush(open_set, (0, start))
    came_from: Dict[Position, Position] = {}
    g_score: Dict[Position, int] = {start: 0}
    f_score: Dict[Position, int] = {start: heuristic_cost_estimate(start, goal)}

    while open_set:
        current = heapq.heappop(open_set)[1]
        if current == goal:
            return reconstruct_path(came_from, current)

        for neighbor in [(0, 1), (0, -1), (1, 0), (-1, 0)]:
            new_row, new_col = current.row + neighbor[0], current.col + neighbor[1]
            if 0 <= new_row < len(grid) and 0 <= new_col < len(grid[0]) and grid[new_row][new_col] == 0:
                tentative_g_score = g_score[current] + 1
                neighbor_pos = Position(new_row, new_col)
                if neighbor_pos not in g_score or tentative_g_score < g_score[neighbor_pos]:
                    came_from[neighbor_pos] = current
                    g_score[neighbor_pos] = tentative_g_score
                    f_score[neighbor_pos] = tentative_g_score + heuristic_cost_estimate(neighbor_pos, goal)
                    heapq.heappush(open_set, (f_score[neighbor_pos], neighbor_pos))

    return []  # No path found
```

