class FileSystem:
    def __init__(self):
        self.root = {'/': {}}
        self.current_path = '/'

    def mkdir(self, directory_name):
        path = self.current_path + directory_name
        if path not in self.root:
            self.root[path] = {}
        else:
            print("Directory already exists")

    def cd(self, directory_name):
        if directory_name == '..':
            if self.current_path != '/':
                self.current_path = '/'.join(self.current_path.split('/')[:-2]) + '/'
        else:
            path = self.current_path + directory_name
            if path in self.root and isinstance(self.root[path], dict):
                self.current_path = path + '/'
            else:
                print("Directory does not exist")

    def touch(self, file_name):
        path = self.current_path + file_name
        if path not in self.root:
            self.root[path] = ''
        else:
            print("File already exists")

    def ls(self):
        contents = [item[1:] if item.startswith('/') else item for item in self.root.keys() if item.startswith(self.current_path)]
        print('\n'.join(contents))

    def cat(self, file_name):
        path = self.current_path + file_name
        if path in self.root and isinstance(self.root[path], str):
            print(self.root[path])
        else:
            print("File does not exist")

