class Simulator {
  constructor(items) {
    this.items = items;
    this.totalMoney = 0;
  }

  viewItems() {
    return this.items.map(({ id, name, price }) => ({ id, name, price }));
  }

  insertCoin(coin) {
    this.totalMoney += coin;
  }

  selectItem(itemId) {
    const selectedItem = this.items.find(item => item.id === itemId);
    if (!selectedItem) {
      return 'Item not available';
    }
    if (selectedItem.quantity === 0) {
      return 'Item out of stock';
    }
    if (this.totalMoney < selectedItem.price) {
      return 'Insufficient funds';
    }

    selectedItem.quantity--;
    const change = this.totalMoney - selectedItem.price;
    this.totalMoney = 0;
    return `Item dispensed: ${selectedItem.name}. Change: ${change.toFixed(2)}`;
  }

  retrieveChange() {
    const change = this.totalMoney;
    this.totalMoney = 0;
    return change;
  }
}
