use std::ffi::OsString;
use std::os::windows::ffi::OsStringExt;
use winapi::um::oleauto::{SysAllocString, SysStringLen, SysStringByteLen, SysFreeString, BSTR};

struct SysString(BSTR);

impl SysString {
    fn new(s: &str) -> SysString {
        let wide_chars: Vec<u16> = OsString::from(s).encode_wide().collect();
        let bstr = unsafe { SysAllocString(wide_chars.as_ptr()) };
        SysString(bstr)
    }

    fn len(&self) -> usize {
        unsafe { SysStringLen(self.0) as usize }
    }

    fn byte_len(&self) -> usize {
        unsafe { SysStringByteLen(self.0) as usize }
    }

    fn is_null(&self) -> bool {
        self.0.is_null()
    }

    fn as_ptr(&self) -> BSTR {
        self.0
    }
}

impl Drop for SysString {
    fn drop(&mut self) {
        unsafe { SysFreeString(self.0) };
    }
}

fn main() {
    let sys_str = SysString::new("Hello, Rust!");
    println!("Length: {}", sys_str.len());
    println!("Byte Length: {}", sys_str.byte_len());
    println!("Is Null: {}", sys_str.is_null());
    println!("Pointer: {:?}", sys_str.as_ptr());
}
```

In this solution, we define a `SysString` struct that wraps a `BSTR` pointer. We implement the `new` method to create a `SysString` from a `&str` by converting it to a wide character representation and allocating a `BSTR` using `SysAllocString`. We also implement the required methods `len`, `byte_len`, `is_null`, and `as_ptr` according to the given specifications. Additionally, we implement the `Drop` trait to free the allocated `BSTR` when the `SysString` goes out of scope. Finally, in the `main` function, we demonstrate the usage of the `SysString` methods.

